from redis import RedisCluster
from datetime import datetime, timedelta

# Define Redis cluster configuration
redis_nodes = [
    {"host": "redis-node1.example.com", "port": 6379},
    {"host": "redis-node2.example.com", "port": 6379},
    # Add additional Redis nodes here
]

# Create Redis cluster object
redis_cluster = RedisCluster(
    startup_nodes=redis_nodes,
    decode_responses=True,
)

# Store sensitive user data in Redis with TTL
def store_sensitive_data(user_id, session_token, api_key):
    redis_cluster.set(f"user:{user_id}:session_token", session_token, ex=timedelta(hours=24))
    redis_cluster.set(f"user:{user_id}:api_key", api_key, ex=timedelta(days=30))

# Retrieve sensitive user data from Redis
def retrieve_sensitive_data(user_id):
    session_token = redis_cluster.get(f"user:{user_id}:session_token")
    api_key = redis_cluster.get(f"user:{user_id}:api_key")
    return session_token, api_key